class PluginExecutor {
  constructor(options = {}) {
    this.timeoutMs = options.timeoutMs || 5000;
    this.maxRequestBodySize = options.maxRequestBodySize || 1048576; // 1MB
  }

  /**
   * Execute a plugin hook with a timeout and error isolation.
   * Plugins receive a sanitized context, not raw req/res objects.
   */
  async executeHook(plugin, hookName, context) {
    if (typeof plugin[hookName] !== 'function') {
      return context;
    }

    // Create a sandboxed context - plugins get limited access
    const sandboxedContext = this._createSandboxedContext(context);

    return new Promise((resolve, reject) => {
      const timer = setTimeout(() => {
        reject(new Error(`Plugin "${plugin.name}" hook "${hookName}" timed out after ${this.timeoutMs}ms`));
      }, this.timeoutMs);

      try {
        const result = plugin[hookName](sandboxedContext);

        if (result && typeof result.then === 'function') {
          result
            .then(res => {
              clearTimeout(timer);
              resolve(this._validateHookResult(plugin.name, hookName, res || sandboxedContext));
            })
            .catch(err => {
              clearTimeout(timer);
              reject(new Error(`Plugin "${plugin.name}" hook "${hookName}" threw: ${err.message}`));
            });
        } else {
          clearTimeout(timer);
          resolve(this._validateHookResult(plugin.name, hookName, result || sandboxedContext));
        }
      } catch (err) {
        clearTimeout(timer);
        reject(new Error(`Plugin "${plugin.name}" hook "${hookName}" threw: ${err.message}`));
      }
    });
  }

  /**
   * Create a limited context object for plugins.
   * Plugins cannot access raw Node.js req/res or server internals.
   */
  _createSandboxedContext(context) {
    return {
      request: {
        method: context.method,
        path: context.path,
        headers: Object.freeze({ ...context.headers }),
        query: Object.freeze({ ...context.query }),
        body: context.body ? JSON.parse(JSON.stringify(context.body)) : undefined,
        ip: context.ip,
      },
      response: {
        statusCode: context.responseStatusCode || 200,
        headers: { ...(context.responseHeaders || {}) },
        body: context.responseBody,
      },
      metadata: {
        timestamp: Date.now(),
        requestId: context.requestId,
      },
      // Plugins can set these to modify behavior
      modifiedHeaders: {},
      modifiedBody: undefined,
      shouldBlock: false,
      blockReason: undefined,
      additionalResponseHeaders: {},
    };
  }

  /**
   * Validate the result returned by a plugin hook.
   */
  _validateHookResult(pluginName, hookName, result) {
    if (typeof result !== 'object' || result === null) {
      throw new Error(`Plugin "${pluginName}" hook "${hookName}" must return an object`);
    }

    // Validate shouldBlock is boolean if set
    if (result.shouldBlock !== undefined && typeof result.shouldBlock !== 'boolean') {
      throw new Error(`Plugin "${pluginName}": shouldBlock must be a boolean`);
    }

    // Validate blockReason is a string if set
    if (result.blockReason !== undefined && typeof result.blockReason !== 'string') {
      throw new Error(`Plugin "${pluginName}": blockReason must be a string`);
    }

    // Sanitize any additional response headers (no injection)
    if (result.additionalResponseHeaders) {
      for (const [key, value] of Object.entries(result.additionalResponseHeaders)) {
        if (typeof key !== 'string' || typeof value !== 'string') {
          throw new Error(`Plugin "${pluginName}": response headers must be string key-value pairs`);
        }
        // Prevent header injection
        if (/[\r\n]/.test(key) || /[\r\n]/.test(value)) {
          throw new Error(`Plugin "${pluginName}": header injection detected`);
        }
        // Prevent overriding security-critical headers
        const forbiddenHeaders = ['transfer-encoding', 'content-length', 'host', 'connection'];
        if (forbiddenHeaders.includes(key.toLowerCase())) {
          throw new Error(`Plugin "${pluginName}": cannot override header "${key}"`);
        }
      }
    }

    return result;
  }
}

