// ============================================================
// Configuration Loading (from file, NOT from env vars with code)
// ============================================================

function loadConfiguration(configPath) {
  if (!configPath || !path.isAbsolute(configPath)) {
    throw new Error('Configuration path must be an absolute path');
  }

  const resolvedPath = path.resolve(configPath);

  if (!fs.existsSync(resolvedPath)) {
    throw new Error(`Configuration file not found: ${resolvedPath}`);
  }

  // Only accept JSON configuration - never eval() config files
  const rawConfig = fs.readFileSync(resolvedPath, 'utf-8');
  let config;

  try {
    config = JSON.parse(rawConfig);
  } catch (err) {
    throw new Error(`Invalid JSON in configuration file: ${err.message}`);
  }

  return config;
}

// ============================================================
// Main Entry Point
// ============================================================

async function main() {
  const configPath = process.env.GATEWAY_CONFIG_PATH;

  if (!configPath) {
    console.error('Error: GATEWAY_CONFIG_PATH environment variable must be set to an absolute path');
    process.exit(1);
  }

  try {
    const config = loadConfiguration(configPath);
    const gateway = new ApiGateway(config);
    await gateway.initialize();

    const port = config.port || 3000;
    await gateway.start(port);
  } catch (err) {
    console.error(`[Gateway] Fatal error: ${err.message}`);
    process.exit(1);
  }
}

// Only run main if this is the entry point
if (require.main === module) {
  main();
}

